class XorBase {
private:
	vector<ll> a; // 线性基基底
	const int MN = 62;

public:
	int rank = 0;
	XorBase() :a(70, 0) {};

	// 插入新数
	void insert(ll x) {
		for (int i = MN; ~i; i--)
			if (x & (1ll << i)) {
				if (!a[i]) {
					// 线性基里没有 x，插入 x
					a[i] = x;
					rank++;
					return;
				}
				x ^= a[i]; // 线性基里有 x
			}
	}
};

var f = Math::factorsAllArray<N>();
void solve(int CASE)
{
	ll n; cin >> n;
	var cnt = vector<ll>(n + 1);
	var xb = XorBase();
	fa(i, 1, n) {
		int a; cin >> a;
		cnt[a]++;
		xb.insert(a);
	}

	// 子序列异或和为 0 的答案
	// 因为异或和为 0，所以这些方案中必然存在一个为空集的情况
	ll ans = Math::fastPow(2, n - xb.rank, mod); 
	ans = (ans - 1 + mod) % mod;

	// 子序列异或和为 max 的答案
	fa(i, 1, n) if (cnt[i]) {
		// max{ S } = i
		// 相当于枚举每个组，这个组里每个数都能被最大的数整除
		// 用线性基算异或和为 max 的答案个数
		ll sum = 0;
		var xb = XorBase();
		for (int p : f[i]) {
			sum += cnt[p];
			if (cnt[p])xb.insert(p);
		}
		ans = (ans + Math::fastPow(2, sum - xb.rank, mod)) % mod;
	}

	cout << ans << endl;
	return;
}
